@app.route('/api/v1/screenshot', methods=['POST'])
@limiter.limit("5 per minute")
@require_api_key
def create_screenshot():
    """Create a screenshot of the provided URL."""
    # Parse request
    if not request.is_json:
        return jsonify({'error': 'Content-Type must be application/json'}), 400

    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid JSON body'}), 400

    url = data.get('url', '').strip()

    # Validate URL
    is_valid, result = validate_url(url)
    if not is_valid:
        return jsonify({'error': result}), 400

    validated_url = result

    try:
        s3_client = get_s3_client()

        # Check cache - return existing screenshot if available
        use_cache = data.get('cache', True)
        if use_cache:
            existing_url = check_existing_screenshot(s3_client, validated_url)
            if existing_url:
                logger.info(f"Cache hit for {validated_url}")
                return jsonify({
                    'success': True,
                    'url': validated_url,
                    'screenshot_url': existing_url,
                    'cached': True,
                    'thumbnail': {
                        'width': THUMBNAIL_WIDTH,
                        'height': THUMBNAIL_HEIGHT,
                    }
                })

        # Take screenshot
        logger.info(f"Taking screenshot of {validated_url}")
        image_bytes = take_screenshot(validated_url)

        # Upload to S3
        s3_key = generate_s3_key(validated_url)
        screenshot_url = upload_to_s3(s3_client, image_bytes, s3_key)

        logger.info(f"Screenshot saved: {s3_key}")

        return jsonify({
            'success': True,
            'url': validated_url,
            'screenshot_url': screenshot_url,
            'cached': False,
            'thumbnail': {
                'width': THUMBNAIL_WIDTH,
                'height': THUMBNAIL_HEIGHT,
            }
        })

    except ValueError as e:
        logger.warning(f"Validation error for {validated_url}: {str(e)}")
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        logger.error(f"Screenshot service error: {str(e)}")
        return jsonify({'error': 'Failed to generate screenshot. Please try again later.'}), 500


@app.route('/api/v1/screenshot', methods=['GET'])
@limiter.limit("10 per minute")
@require_api_key
def get_screenshot():
    """Get a screenshot URL for the provided URL (uses cache or generates new)."""
    url = request.args.get('url', '').strip()

    # Validate URL
    is_valid, result = validate_url(url)
    if not is_valid:
        return jsonify({'error': result}), 400

    validated_url = result

    try:
        s3_client = get_s3_client()

        # Check cache first
        existing_url = check_existing_screenshot(s3_client, validated_url)
        if existing_url:
            return jsonify({
                'success': True,
                'url': validated_url,
                'screenshot_url': existing_url,
                'cached': True,
            })

        # No cached version, generate new
        image_bytes = take_screenshot(validated_url)
        s3_key = generate_s3_key(validated_url)
        screenshot_url = upload_to_s3(s3_client, image_bytes, s3_key)

        return jsonify({
            'success': True,
            'url': validated_url,
            'screenshot_url': screenshot_url,
            'cached': False,
        })

    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        logger.error(f"Screenshot service error: {str(e)}")
        return jsonify({'error': 'Failed to generate screenshot.'}), 500


